    while(T--){
        int N; cin>>N;
        vector<long long> a(N);
        for(int i=0;i<N;i++) cin>>a[i];
        sort(a.begin(), a.end());
        long long ans = a[N/2] - a[N/2 - 1];
        cout<<ans<<"\n";
    }
