const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  let arr = new Array(N);
  for (let i = 0; i < N; i++) arr[i] = Number(input[idx++]);
  arr.sort((a, b) => a - b);
  const ans = arr[Math.floor(N / 2)] - arr[Math.floor(N / 2) - 1];
  results.push(String(ans));
}
